(3,	'showdoc接口key',	'showdoc_api_key',	'afab842e525e8d5627426549937815ba757753575',	NULL,	0),
(4,	'showdoc接口token',	'showdoc_api_token',	'f4bb8e2d44c614a1dd26ebd8130b5098246966623',	NULL,	0),
(5,	'优惠券的限制商品改为限制分类',	'coupon_permit_category',	'0',	'checkbox-app|切换',	0),
(6,	'商品图册数量',	'goods_image_num',	'9',	'number',	0),
(7,	'商品规格项目数量',	'goods_spec_num',	'3',	'number',	0),
(8,	'商品分利层级数量',	'goods_commission_num',	'3',	'number',	0),
(9,	'订单退货退款地址',	'order_refund_address',	'广东广州市天河区',	'',	0),
(51,	'网站状态，0关闭，1开启',	'site_status',	'1',	'checkbox-app|开启',	0),
(52,	'提现手续费 (带上百分号即按百分比计算)',	'withdraw_fee',	'20%',	'',	1),
(53,	'最低提现数',	'withdraw_least',	'20',	'number',	1),
(54,	'盲盒每天开启时间',	'blind_begin',	'00:00',	'date||showCal=\"false\" format=\"hh:nn\"',	1),
(55,	'盲盒每天关闭时间',	'blind_end',	'00:00',	'date||showCal=\"false\" format=\"hh:nn\"',	1),
(56,	'首页游戏玩法',	'game_rule2',	'踩气球游戏玩法：经历了踩气球这样的体力游戏，同学们分组完成猜数字游戏。数字1-100被打乱摆放在地上，每一组10名同学按照1到100的顺序依次找出每个数字。考验同学们的观察力和团队协作能力。 萝卜蹲游戏玩法：分成四组，各自取一个蔬菜名，被喊到......',	'textarea',	1),
(57,	'首页游戏玩法 (英文版)',	'game_rule3',	'How to play the game of stepping on balloons: after experiencing physical games such as stepping on balloons, the students completed the number guessing game in groups. The numbers 1-100 were placed on the ground disorderly. Each group of 10 students found out each number in the order of 1 to 100. Test the students\' ability of observation and teamwork. How to play the radish squat game: divide into four groups, choose a vegetable name, and be called',	'textarea',	1),
(58,	'首页游戏地址 (一行一个)',	'game_url',	'http://www.baidu.com\nhttp://www.google.com\nhttp://www.aliyun.com',	'textarea',	1),
(59,	'等级说明',	'grade_memo2',	'1.踩气球游戏玩法：经历了踩气球这样的体力游戏，同学们分组完成猜数字游戏。数字1-100被打乱摆放在地上，每一组10名同学按照1到100的顺序依次找出每个数字。考验同学们的观察力和团队协作能力。 \n\n2.萝卜蹲游戏玩法：分成四组，各自取一个蔬菜名，被喊到的队伍必须蹲下来，并喊出下一个队伍的名字，蹲错或喊错的队伍被淘汰。\n\n 3.抢坐椅子游戏玩法：听着音乐随着椅子转，当音乐停下时，未做到椅子的被淘汰，每次音乐减少一只椅子，最后两人剩一把椅子，坐到椅子的胜出。 \n\n4.跳跳球游戏玩法：双脚夹着皮球跳跃，接力，如果皮球掉了，需要回到位置上重新出发，最先完成皮球传递任务的队伍胜出。',	'textarea',	1),
(60,	'等级说明 (英文版)',	'grade_memo3',	'1. how to play the game of stepping on balloons: after experiencing physical games such as stepping on balloons, the students completed the number guessing game in groups. The numbers 1-100 were placed on the ground disorderly. Each group of 10 students found out each number in the order of 1 to 100. Test the students\' ability of observation and teamwork.\n\n2. playing method of radish squat game: divide into four groups and choose a vegetable name. The team that is called must squat down and shout the name of the next team. The team that squats or cries wrong will be eliminated.\n\n3. how to play the game of grabbing chairs: listen to the music and turn with the chairs. When the music stops, those who fail to do so will be eliminated. Each time the music reduces one chair, the last two people will have one chair left, and the one who sits on the chair will win.\n\n4. how to play the jump ball game: jump with the ball between your feet and relay. If the ball falls, you need to go back to the position and start again. The team that completes the ball passing task first wins.',	'textarea',	1),
(61,	'提现说明',	'withdraw_memo2',	'1、打开第三方数字钱包，扫码或复制地址转账。\n2、请转入100~10万 TRX 或 10~2万个TRC20的USDT投注，低于或高于限定数量不能参与抽奖。低于下限不退回,高于上限扣除10% 手续费原路退回。\n3、如果中奖，立即返1.99倍奖金转入您的钱包。\n4、中奖规则：转账金额的个位数和区块哈希值(Blockhash)最后的数字（只看数字，不看字母）同为单数或同为双数时，则成功中奖。\n5、请注意只能用去中心化钱包投注，如使用交易所钱包投注无法返奖，也无法追回。',	'textarea',	1),
(62,	'提现说明 (英文版)',	'withdraw_memo3',	'1. Open the third-party digital wallet, scan the code or copy the address for transfer.\n2. Please transfer to usdt bets of 1-100000 TRX or 100000-20000 trc20s. If the number is lower or higher than the limit, you cannot participate in the lottery. If it is lower than the lower limit, it will not be returned. If it is higher than the upper limit, 10% of the handling fee will be deducted and returned in the same way.\n3. If you win the prize, you will immediately return 1.99 times of the bonus to your wallet.\n4. Winning rule: if the single digits of the transfer amount and the last digit of the blockhash value (only numbers, not letters) are both singular or even numbers, the winning will be successful.\n5. Please note that only the decentralized wallet can be used for betting. If the exchange wallet is used for betting, the prize cannot be returned or recovered.',	'textarea',	1),
(63,	'计算器：每日预计收益比例，单位%',	'counter_percent',	'1',	'number',	1),
(64,	'计算器：最大天数',	'counter_day',	'100',	'number',	1),
(65,	'计算器：最大团队人数',	'counter_people',	'300',	'number',	1),
(66,	'1USDT兑换积分',	'usdt_integral',	'2',	NULL,	1),
(67,	'复投可得积分 (%)',	'reinvest_integral',	'20',	NULL,	1),
(68,	'积分说明',	'integral_memo2',	NULL,	'textarea',	1),
(69,	'积分说明 (英文版)',	'integral_memo3',	NULL,	'textarea',	1),
(70,	'充值说明',	'recharge_memo2',	NULL,	'textarea',	1),
(71,	'充值说明 (英文版)',	'recharge_memo3',	NULL,	'textarea',	1);
