  `weight` decimal(10,2) DEFAULT '0.00' COMMENT '重量kg',
  `free_shipping_count` int(11) DEFAULT '0' COMMENT '购买n件起包邮',
  `commission_type` int(11) DEFAULT '0' COMMENT '佣金分利类型，0关闭，1百分比，2固定金额',
