  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(30) DEFAULT NULL COMMENT '分组名称',
  `menu` varchar(200) DEFAULT NULL COMMENT '菜单权限',
  `permission` text COMMENT '权限',
  `power` int(11) DEFAULT '0' COMMENT '是否超级组别',
  `add_time` int(11) DEFAULT '0' COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=COMPACT COMMENT='管理员组别';


DROP TABLE IF EXISTS `hi_manage_log`;
CREATE TABLE `hi_manage_log` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `manage_id` int(11) DEFAULT '0' COMMENT '管理员id',
  `manage_name` varchar(20) DEFAULT NULL COMMENT '管理员账号',
  `app` varchar(100) DEFAULT NULL COMMENT '控制器',
  `act` varchar(100) DEFAULT NULL COMMENT '方法',
  `type` varchar(20) DEFAULT NULL COMMENT '类型，url路径，insert插入数据，update更新数据，delete删除数据',
  `remark` text COMMENT '内容',
  `ip` varchar(20) DEFAULT NULL COMMENT 'ip',
  `add_time` int(11) DEFAULT '0' COMMENT '添加时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='管理员日志';


SET NAMES utf8mb4;

DROP TABLE IF EXISTS `hi_member`;
CREATE TABLE `hi_member` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) DEFAULT NULL COMMENT '用户名称',
  `password` varchar(128) DEFAULT NULL COMMENT '密码，加密后',
  `salt` varchar(6) DEFAULT NULL COMMENT '盐值',
  `token` varchar(128) DEFAULT NULL COMMENT '签名',
  `session_id` varchar(100) DEFAULT NULL COMMENT 'session_id',
  `withdraw_password` varchar(128) DEFAULT NULL COMMENT '提现密码',
  `withdraw_salt` varchar(6) DEFAULT NULL COMMENT '提现盐值',
  `pay_password` varchar(128) DEFAULT NULL COMMENT '支付密码',
  `pay_salt` varchar(128) DEFAULT NULL COMMENT '支付盐值',
  `parent_id` int(11) DEFAULT '0' COMMENT '我的邀请人',
  `parent_tree` varchar(1000) DEFAULT '' COMMENT '我的祖辈树',
  `grade_id` int(11) DEFAULT '0' COMMENT '会员等级',
  `grade_score` int(11) DEFAULT '0' COMMENT '等级积分',
  `grade_time` int(11) DEFAULT '0' COMMENT '等级开始时间',
  `grade_endtime` int(11) DEFAULT '0' COMMENT '等级结束时间',
  `money` decimal(20,8) DEFAULT '0.00000000' COMMENT '余额',
  `commission` decimal(20,2) DEFAULT '0.00' COMMENT '佣金',
  `commission_total` decimal(20,2) DEFAULT '0.00' COMMENT '总收益',
  `integral` decimal(20,2) DEFAULT '0.00' COMMENT '积分',
  `invite_code` varchar(50) DEFAULT NULL COMMENT '邀请码',
  `real_name` varchar(50) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '真实姓名',
  `nick_name` varchar(250) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '昵称',
  `mobile` varchar(50) DEFAULT NULL COMMENT '手机',
  `email` varchar(50) DEFAULT NULL COMMENT '邮箱',
  `avatar` varchar(1000) DEFAULT NULL COMMENT '头像',
  `wechat` varchar(50) DEFAULT NULL COMMENT '微信号',
  `qq` varchar(50) DEFAULT NULL COMMENT 'QQ号',
  `idcard` varchar(50) DEFAULT NULL COMMENT '身份证号码',
  `sex` varchar(50) DEFAULT NULL COMMENT '性别',
  `province` varchar(50) DEFAULT NULL COMMENT '省',
  `city` varchar(50) DEFAULT NULL COMMENT '市',
  `district` varchar(50) DEFAULT NULL COMMENT '区',
  `town` varchar(50) DEFAULT NULL COMMENT '街道',
  `birth_year` int(11) DEFAULT '0' COMMENT '出生年',
  `birth_month` int(11) DEFAULT '0' COMMENT '出生月',
  `birth_day` int(11) DEFAULT '0' COMMENT '出生日',
  `remark` varchar(200) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '个性签名',
  `status` int(11) DEFAULT '0' COMMENT '0冻结，1正常',
  `logins` int(11) DEFAULT '0' COMMENT '登录次数',
  `last_ip` varchar(50) DEFAULT '' COMMENT '上次登录ip',
  `last_time` int(11) DEFAULT '0' COMMENT '上次登录时间',
  `reg_ip` varchar(50) DEFAULT '' COMMENT '注册ip',
  `reg_time` int(11) DEFAULT '0' COMMENT '注册时间',
  PRIMARY KEY (`id`),
  KEY `name` (`name`),
  KEY `parent_id` (`parent_id`),
  KEY `parent_tree` (`parent_tree`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='会员表';


DROP TABLE IF EXISTS `hi_member_commission`;
CREATE TABLE `hi_member_commission` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `member_id` int(11) DEFAULT '0' COMMENT '会员id',
  `commission` decimal(10,2) DEFAULT NULL COMMENT '佣金金额',
  `memo` varchar(250) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '佣金收入来源',
  `type` int(11) DEFAULT '0' COMMENT '产生来源，1订单，2充值，3注册邀请',
  `parent_id` int(11) DEFAULT '0' COMMENT '产生的id',
  `status` int(11) DEFAULT '1' COMMENT '-1退款，0冻结，1正常（已到会员）',
  `add_time` int(11) DEFAULT '0' COMMENT '添加时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='会员佣金表';


DROP TABLE IF EXISTS `hi_member_favorite`;
CREATE TABLE `hi_member_favorite` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `member_id` int(11) DEFAULT '0' COMMENT '会员id',
  `item_id` int(11) DEFAULT '0' COMMENT '收藏内容的id',
  `type` int(11) DEFAULT '0' COMMENT '收藏内容的类型，1商品，2店铺，3文章，4会员',
  `add_time` int(11) DEFAULT '0' COMMENT '收藏时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='会员收藏表';


DROP TABLE IF EXISTS `hi_member_grade`;
CREATE TABLE `hi_member_grade` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(250) DEFAULT NULL COMMENT '等级名称',
  `pic` varchar(250) DEFAULT NULL COMMENT '图片',
  `memo` text COMMENT '备注',
  `num` int(11) DEFAULT '0' COMMENT '数量',
  `person` int(11) DEFAULT '3' COMMENT '升级条件(下级人数)',
  `score` int(11) DEFAULT '0' COMMENT '所需积分',
  `price` decimal(20,2) DEFAULT '0.00' COMMENT '价格',
  `level_percent` decimal(20,1) DEFAULT '0.0' COMMENT '级别收益，百分比',
  `line_percent` decimal(20,1) DEFAULT '0.0' COMMENT '平级收益，百分比',
  `recommend` decimal(20,1) DEFAULT '0.0' COMMENT '购买后上级收益，百分比',
  `status` int(11) DEFAULT '1' COMMENT '状态：1正常，0隐藏',
  `sort` int(11) DEFAULT '999' COMMENT '数字越小，排在越前',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='会员等级表';


DROP TABLE IF EXISTS `hi_member_grade_order`;
CREATE TABLE `hi_member_grade_order` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `member_id` int(11) DEFAULT '0' COMMENT '会员id',
  `grade_id` int(11) DEFAULT '0' COMMENT '等级id',
  `hash` varchar(500) DEFAULT NULL COMMENT 'MetaMask返回的hash',
  `price` decimal(20,2) DEFAULT '0.00' COMMENT '价格',
  `is_balance` int(11) DEFAULT '0' COMMENT '是否使用余额支付',
  `status` int(11) DEFAULT '0' COMMENT '状态，0未生效，1已完成',
  `add_time` int(11) DEFAULT '0' COMMENT '添加时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='会员等级';


DROP TABLE IF EXISTS `hi_member_wallet`;
CREATE TABLE `hi_member_wallet` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `member_id` int(11) DEFAULT '0' COMMENT '会员id',
  `type` int(11) DEFAULT '1' COMMENT '钱包类型，1MetaMask，2TronLink',
  `wallet` varchar(200) DEFAULT NULL COMMENT '钱包地址',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='会员钱包地址';


DROP TABLE IF EXISTS `hi_menu`;
CREATE TABLE `hi_menu` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) DEFAULT NULL COMMENT '名称',
  `parent_id` int(11) DEFAULT '0' COMMENT '上级id',
  `path` varchar(100) DEFAULT NULL COMMENT '路径',
  `icon` varchar(100) DEFAULT NULL COMMENT '图标',
  `level` int(11) DEFAULT '1' COMMENT '层级，0隐藏，1根目录，2子目录',
  `sort` int(11) DEFAULT '1' COMMENT '排序，越小越前',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=COMPACT COMMENT='导航';


DROP TABLE IF EXISTS `hi_money_log`;
CREATE TABLE `hi_money_log` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `member_id` int(11) DEFAULT '0' COMMENT '来源会员的id',
  `number` decimal(20,8) DEFAULT '0.00000000' COMMENT '变化的数量',
  `old` decimal(20,8) DEFAULT '0.00000000' COMMENT '原来的数值',
  `new` decimal(20,8) DEFAULT '0.00000000' COMMENT '变化后的数值',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `type` int(11) DEFAULT '0' COMMENT '1充值，2提现，...',
  `status` int(11) DEFAULT '0' COMMENT '0支出，1收入',
  `money_type` int(11) DEFAULT '0' COMMENT '钱包类型，1USDT，2BTC，3EXP',
  `fromid` int(11) DEFAULT '0' COMMENT '来源id',
  `fromtable` varchar(255) DEFAULT NULL COMMENT '所属表',
  `fee` decimal(20,8) DEFAULT '0.00000000' COMMENT '手续费',
  `add_time` int(11) DEFAULT '0' COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `user_id` (`member_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='账变记录表';


DROP TABLE IF EXISTS `hi_order`;
CREATE TABLE `hi_order` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `member_id` int(11) DEFAULT '0' COMMENT '会员id',
  `shop_id` int(11) DEFAULT '0' COMMENT '订单直接销售店铺id',
  `reseller_id` int(11) DEFAULT '0' COMMENT '邀请人id',
  `type` int(11) DEFAULT '0' COMMENT '订单类型，0普通，1拼团，2秒杀，3砍价',
  `parent_id` int(11) DEFAULT '0' COMMENT '所属订单类型主id',
  `order_sn` varchar(50) DEFAULT NULL COMMENT '订单单号',
  `pay_order_sn` varchar(50) DEFAULT NULL COMMENT '订单号(重新支付时会变)',
  `parent_order_sn` varchar(50) DEFAULT NULL COMMENT '父订单SN（有分单时，需要通过此单号来记录子订单）',
  `total_price` decimal(10,2) DEFAULT '0.00' COMMENT '订单总价',
  `status` int(11) DEFAULT '0' COMMENT '0未支付，1已支付，2已发货，3完成（已收货），4完成（已评价），-1取消，-2退款，-3退货',
  `shown` int(11) DEFAULT '1' COMMENT '是否对用户显示，0隐藏，1显示',
  `add_time` int(11) DEFAULT '0' COMMENT '下单时间',
  `trade_no` varchar(200) DEFAULT NULL COMMENT '外部订单号',
  `total_fee` decimal(10,2) DEFAULT '0.00' COMMENT '支付金额',
  `pay_method` varchar(50) DEFAULT 'alipay' COMMENT 'alipay/wxpay/wxpay_h5/wxpay_mini',
  `client_type` int(11) DEFAULT '0' COMMENT '客户端类型，0网页，1小程序，2iOS，3Android',
  `pay_time` int(11) DEFAULT '0' COMMENT '付款时间',
  `shipping_time` int(11) DEFAULT '0' COMMENT '发货时间',
  `shouhuo_time` int(11) DEFAULT '0' COMMENT '收货时间',
  `ask_refund_time` int(11) DEFAULT '0' COMMENT '申请退货退款时间',
  `refund_time` int(11) DEFAULT '0' COMMENT '退货退款时间',
  `edit_time` int(11) DEFAULT '0' COMMENT '修改时间',
  `cancel_time` int(11) DEFAULT '0' COMMENT '取消时间',
  `province` varchar(50) DEFAULT NULL COMMENT '省',
  `city` varchar(50) DEFAULT NULL COMMENT '市',
  `district` varchar(50) DEFAULT NULL COMMENT '区',
  `address` varchar(250) DEFAULT NULL COMMENT '地址',
  `zipcode` varchar(10) DEFAULT NULL COMMENT '邮政编码',
  `name` varchar(50) DEFAULT NULL COMMENT '收货人姓名',
  `idcard` varchar(50) DEFAULT NULL COMMENT '身份证号码',
  `mobile` varchar(100) DEFAULT NULL COMMENT '手机号码',
  `memo` varchar(1000) DEFAULT NULL COMMENT '买家留言',
  `shipping_price` decimal(10,2) DEFAULT '0.00' COMMENT '运费',
  `discount_price` decimal(10,2) DEFAULT '0.00' COMMENT '折扣',
  `shipping_company` varchar(200) DEFAULT NULL COMMENT '快递公司',
  `shipping_number` varchar(200) DEFAULT NULL COMMENT '快递单号',
  `coupon_sn` varchar(50) DEFAULT NULL COMMENT '优惠券id',
  `ip` varchar(50) DEFAULT NULL COMMENT '下单ip',
  `delay_shouhuo_time` int(11) DEFAULT '0' COMMENT '提交延迟收货时间',
  `ask_shipping_time` int(11) DEFAULT '0' COMMENT '提醒发货时间',
  `reseller_read_time` int(11) DEFAULT '0' COMMENT '渠道商是否查看了该订单',
  `factory_read_time` int(11) DEFAULT '0' COMMENT '厂家是否查看了该订单',
  `handle_after_paid` int(11) DEFAULT '0' COMMENT '是否已处理库存、发送通知等',
  `invoice_type` varchar(200) DEFAULT NULL COMMENT '发票类型，分个人/公司',
  `invoice_name` varchar(200) DEFAULT NULL COMMENT '发票抬头',
  `invoice_content` varchar(200) DEFAULT NULL COMMENT '发票内容',
  `used_commission` decimal(10,2) DEFAULT '0.00' COMMENT '使用佣金支付',
  `used_money` decimal(10,2) DEFAULT '0.00' COMMENT '使用余额支付',
  `used_coupon` decimal(10,2) DEFAULT '0.00' COMMENT '使用优惠券支付',
  `readed` int(11) DEFAULT '0' COMMENT '0未看，1已看',
  `integral_order` int(11) DEFAULT '0' COMMENT '是否积分商城订单',
  `used_integral` decimal(10,2) DEFAULT '0.00' COMMENT '使用积分抵现',
  `integral` int(11) DEFAULT '0' COMMENT '使用了多少积分',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='订单表';


DROP TABLE IF EXISTS `hi_order_goods`;
CREATE TABLE `hi_order_goods` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `member_id` int(11) DEFAULT '0' COMMENT '会员id',
  `shop_id` int(11) DEFAULT '0' COMMENT '店铺id',
  `order_id` int(11) DEFAULT '0' COMMENT '订单id',
  `goods_id` int(11) DEFAULT '0' COMMENT '商品id',
  `goods_name` varchar(250) DEFAULT NULL COMMENT '商品名称',
  `goods_pic` varchar(250) DEFAULT NULL COMMENT '商品主图',
  `spec_linkage` varchar(100) DEFAULT NULL COMMENT '规格id树，逗号隔开',
  `spec` varchar(200) DEFAULT NULL COMMENT '规格',
  `price` decimal(10,2) DEFAULT '0.00' COMMENT '价格(单价*数量)',
  `single_price` decimal(10,2) DEFAULT '0.00' COMMENT '单价(购买商品当时价格)',
  `quantity` int(11) DEFAULT '1' COMMENT '购买数量',
  `qrcode` varchar(250) DEFAULT NULL COMMENT '条形码/二维码',
  `comment_stars` int(11) DEFAULT '5' COMMENT '评价打分',
  `comment_pic` varchar(1000) DEFAULT NULL COMMENT '评价图片',
  `comment_content` varchar(1000) DEFAULT NULL COMMENT '评价内容',
  `comment_time` int(11) DEFAULT '0' COMMENT '评价时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='订单商品表';


DROP TABLE IF EXISTS `hi_order_refund`;
CREATE TABLE `hi_order_refund` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `order_id` int(11) DEFAULT '0' COMMENT '订单id',
  `member_id` int(11) DEFAULT '0' COMMENT '会员id',
  `shop_id` int(11) DEFAULT '0' COMMENT '店铺id',
  `pay_method` varchar(50) DEFAULT NULL COMMENT '原订单的支付方式',
  `out_refund_no` varchar(50) DEFAULT NULL COMMENT '本站退款订单号',
  `type` int(11) DEFAULT '0' COMMENT '1退款，2退货',
  `reason` varchar(500) DEFAULT NULL COMMENT '退款理由',
  `price` decimal(10,2) DEFAULT '0.00' COMMENT '退款金额',
  `memo` varchar(500) DEFAULT NULL COMMENT '退款备注',
  `pic1` varchar(250) DEFAULT NULL COMMENT '退款拍照图',
  `pic2` varchar(250) DEFAULT NULL COMMENT '退款拍照图',
  `pic3` varchar(250) DEFAULT NULL COMMENT '退款拍照图',
  `status` int(11) DEFAULT '0' COMMENT '状态，0申请，1成功',
  `add_time` int(11) DEFAULT '0' COMMENT '添加时间',
  `audit_memo` varchar(500) DEFAULT NULL COMMENT '审核理由',
  `audit_time` int(11) DEFAULT '0' COMMENT '审核时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='退款/退货表';


DROP TABLE IF EXISTS `hi_province`;
CREATE TABLE `hi_province` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `province_id` int(11) DEFAULT '0' COMMENT '省份id',
  `name` varchar(20) DEFAULT NULL COMMENT '名称',
  PRIMARY KEY (`id`),
  KEY `province_id` (`province_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='省份表';


DROP TABLE IF EXISTS `hi_recharge_log`;
CREATE TABLE `hi_recharge_log` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `member_id` int(11) DEFAULT '0',
  `num` int(11) DEFAULT '0',
  `pic` varchar(1000) DEFAULT NULL,
  `status` int(11) DEFAULT '0',
  `add_time` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;


DROP TABLE IF EXISTS `hi_shipping_company`;
CREATE TABLE `hi_shipping_company` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(50) DEFAULT NULL COMMENT '快递公司名称',
  `pinyin` varchar(50) DEFAULT NULL COMMENT '快递拼音，如EMS、YTO',
  `sort` int(11) DEFAULT '999' COMMENT '数字越小，排在越前',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='快递公司表';


DROP TABLE IF EXISTS `hi_shipping_fee`;
CREATE TABLE `hi_shipping_fee` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(20) DEFAULT NULL COMMENT '模板名称',
  `type` int(11) DEFAULT '0' COMMENT '类型，0按重量，1按件数',
  `first` int(11) DEFAULT '0' COMMENT '首重(件)',
  `first_price` decimal(10,2) DEFAULT '0.00' COMMENT '运费',
  `second` int(11) DEFAULT '0' COMMENT '续重(件)',
  `second_price` decimal(10,2) DEFAULT '0.00' COMMENT '续费',
  `add_time` int(11) DEFAULT '0' COMMENT '添加时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='运费模板';


DROP TABLE IF EXISTS `hi_shipping_fee_area`;
CREATE TABLE `hi_shipping_fee_area` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `shipping_fee_id` int(11) DEFAULT '0' COMMENT '运费模板id',
  `districts` text COMMENT '区域id',
  `first` int(11) DEFAULT '0' COMMENT '首重(件)',
  `first_price` decimal(10,2) DEFAULT '0.00' COMMENT '运费',
  `second` int(11) DEFAULT '0' COMMENT '续重(件)',
  `second_price` decimal(10,2) DEFAULT '0.00' COMMENT '续费',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='运费模板配送区域';


DROP TABLE IF EXISTS `hi_shop`;
CREATE TABLE `hi_shop` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(250) DEFAULT NULL COMMENT '店铺名称',
  `member_id` int(11) DEFAULT '0' COMMENT '所属会员',
  `avatar` varchar(250) DEFAULT NULL COMMENT '店铺头像',
  `poster_pic` varchar(250) DEFAULT NULL COMMENT '店铺店招图片',
  `goods` int(11) DEFAULT '0' COMMENT '商品数量',
  `resellers` int(11) DEFAULT '0' COMMENT '渠道商数量',
  `followers` int(11) DEFAULT '0' COMMENT '关注者数量',
  `clicks` int(11) DEFAULT '0' COMMENT '店铺被访问的次数',
  `province` varchar(50) DEFAULT NULL COMMENT '联系地址-省',
  `city` varchar(50) DEFAULT NULL COMMENT '联系地址-市',
  `district` varchar(50) DEFAULT NULL COMMENT '联系地址-区',
  `address` varchar(250) DEFAULT NULL COMMENT '联系地址-地址',
  `mobile` varchar(100) DEFAULT NULL COMMENT '手机',
  `tel` varchar(250) DEFAULT NULL COMMENT '固定电话',
  `qq` varchar(100) DEFAULT NULL,
  `weixin` varchar(100) DEFAULT NULL,
  `email` varchar(250) DEFAULT NULL,
  `contacter` varchar(50) DEFAULT NULL COMMENT '联系人/法人',
  `type_id` int(11) DEFAULT '0' COMMENT '主营类目',
  `shop_type` int(11) DEFAULT '0' COMMENT '店铺类型，1渠道商店铺（不显示），2厂家店铺',
  `status` int(11) DEFAULT '0' COMMENT '-1冻结，0等待审核，1正常',
  `add_time` int(11) DEFAULT '0' COMMENT '添加时间',
  `audit_time` int(11) DEFAULT '0' COMMENT '审核时间',
  `description` varchar(500) DEFAULT NULL COMMENT '店铺简介',
  `return_province` varchar(50) DEFAULT NULL COMMENT '退货地址-省',
  `return_city` varchar(50) DEFAULT NULL COMMENT '退货地址-省',
  `return_district` varchar(50) DEFAULT NULL COMMENT '退货地址-省',
  `return_address` varchar(50) DEFAULT NULL COMMENT '退货地址-省',
  `return_name` varchar(50) DEFAULT NULL COMMENT '退货地址-联系人',
  `return_mobile` varchar(50) DEFAULT NULL COMMENT '退货地址-电话',
  `orders` int(11) DEFAULT '0' COMMENT '店铺订单总数',
  `week_orders` int(11) DEFAULT '0' COMMENT '7天订单数',
  `total_income` decimal(10,2) DEFAULT '0.00' COMMENT '总收入',
  `week_income` decimal(10,2) DEFAULT '0.00' COMMENT '周收入',
  `can_withdraw_money` decimal(11,2) DEFAULT '0.00' COMMENT '可提取的金额',
  `withdrawed_money` decimal(11,2) DEFAULT '0.00' COMMENT '已结算的金额',
  `withdrawing_money` decimal(11,2) DEFAULT '0.00' COMMENT '正在结算的金额',
  `longitude` double DEFAULT '0' COMMENT '纬度',
  `latitude` double DEFAULT '0' COMMENT '经度',
  `sort` int(11) DEFAULT '999' COMMENT '数字越小，排在越前',
  `wifi` int(11) DEFAULT '1' COMMENT '免费WIFI',
  `pickup` int(11) DEFAULT '0' COMMENT '门店取货',
  `app_discount` decimal(10,1) DEFAULT '0.0' COMMENT 'APP下单折扣',
  `business_time` varchar(250) DEFAULT NULL COMMENT '营业时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='店铺表';


DROP TABLE IF EXISTS `hi_town`;
CREATE TABLE `hi_town` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `town_id` bigint(20) DEFAULT '0' COMMENT '街道id',
  `name` varchar(40) DEFAULT NULL COMMENT '名称',
  `parent_id` int(11) DEFAULT '0' COMMENT '上级id',
  PRIMARY KEY (`id`),
  KEY `town_id` (`town_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='街道表';


DROP TABLE IF EXISTS `hi_withdraw`;
CREATE TABLE `hi_withdraw` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `member_id` int(11) DEFAULT '0' COMMENT '会员id',
  `order_sn` varchar(50) DEFAULT NULL COMMENT '订单号',
  `trade_no` varchar(250) DEFAULT NULL COMMENT '外部订单号',
  `pay_method` varchar(50) DEFAULT 'wxpay_h5' COMMENT 'alipay/wxpay/wxpay_h5',
  `client_type` int(11) DEFAULT '0' COMMENT '客户端类型，0网页，1小程序，2iOS，3Android',
  `pay_time` int(11) DEFAULT '0' COMMENT '付款时间',
  `withdraw_money` decimal(20,2) DEFAULT '0.00' COMMENT '提现金额(含手续费)',
  `withdraw_fee` decimal(20,2) DEFAULT '0.00' COMMENT '提现手续费',
  `name` varchar(50) DEFAULT NULL COMMENT '真实姓名',
  `bank_name` varchar(50) DEFAULT NULL COMMENT '银行名称',
  `bank_branch` varchar(100) DEFAULT NULL COMMENT '支行名称',
  `bank_card` varchar(50) DEFAULT NULL COMMENT '银行卡号',
  `alipay` varchar(50) DEFAULT NULL COMMENT '支付宝账号',
  `mobile` varchar(20) DEFAULT NULL COMMENT '手机号码',
  `withdraw_wallet` varchar(500) DEFAULT NULL COMMENT '提现地址',
  `person_income` int(11) DEFAULT '0' COMMENT '个人所得税',
  `invoice_number` varchar(200) DEFAULT NULL COMMENT '发票单号',
  `shipping_number` varchar(200) DEFAULT NULL COMMENT '快递单号',
  `shipping_company` varchar(200) DEFAULT NULL COMMENT '快递公司',
  `type` int(11) DEFAULT '0' COMMENT '资金来源(member表的字段)，commission佣金',
  `ip` varchar(50) DEFAULT NULL COMMENT '提现人ip',
  `status` int(11) DEFAULT '0' COMMENT '0等待审核，1提现成功，-1提现失败',
  `add_time` int(11) DEFAULT '0' COMMENT '提现申请日期',
  `audit_memo` varchar(250) DEFAULT NULL COMMENT '审核备注',
  `audit_adminid` int(11) DEFAULT '0' COMMENT '审单人ID',
  `audit_admin` varchar(50) DEFAULT NULL COMMENT '审单人',
  `audit_time` int(11) DEFAULT '0' COMMENT '审单时间',
  `withdraw_memo` varchar(250) DEFAULT NULL COMMENT '提现结果的备注，如流水号',
  `withdraw_adminid` int(11) DEFAULT '0' COMMENT '提现操作人ID',
  `withdraw_admin` varchar(50) DEFAULT NULL COMMENT '提现操作人',
  `withdraw_time` int(11) DEFAULT '0' COMMENT '提现操作时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='提现表';


